import requests
import json

# Set your Kong admin API credentials
KONG_ADMIN_API_URL = 'http://localhost:8001'
KONG_ADMIN_API_KEY = 'your-admin-api-key'

def create_service(service_name, host):
    url = f'{KONG_ADMIN_API_URL}/services'
    headers = {'Content-Type': 'application/json', 'Authorization': f'Bearer {KONG_ADMIN_API_KEY}'}
    data = {
        'name': service_name,
        'host': host
    }
    response = requests.post(url, headers=headers, json=data)
    if response.status_code == 201:
        print(f'Service created: {service_name}')
    else:
        print(f'Failed to create service: {response.text}')

def create_route(service_name):
    url = f'{KONG_ADMIN_API_URL}/routes'
    headers = {'Content-Type': 'application/json', 'Authorization': f'Bearer {KONG_ADMIN_API_KEY}'}
    data = {
        'protocols': ['http'],
        'paths': [f'/api/{service_name}']
    }
    response = requests.post(url, headers=headers, json=data)
    if response.status_code == 201:
        print(f'Route created for service: {service_name}')
    else:
        print(f'Failed to create route for service: {response.text}')

def create_upstream(service_name):
    url = f'{KONG_ADMIN_API_URL}/services/{service_name}/upstreams'
    headers = {'Content-Type': 'application/json', 'Authorization': f'Bearer {KONG_ADMIN_API_KEY}'}
    data = {
        'name': service_name,
        'algorithm': 'round-robin',
        'upstream_groups': [
            {
                'name': service_name,
                'upstreams': [
                    {
                        'name': service_name,
                        'target': f'http://{service_name}.com:80'
                    }
                ]
            }
        ]
    }
    response = requests.post(url, headers=headers, json=data)
    if response.status_code == 201:
        print(f'Upstream created for service: {service_name}')
    else:
        print(f'Failed to create upstream for service: {response.text}')

# Create a new service
create_service('my-service', 'localhost')

# Create a route for the service
create_route('my-service')

# Create an upstream target for the service
create_upstream('my-service')